import { Link, useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function CategoryPage() {

  const { category } = useParams()

  const filteredProducts = printProducts.filter(
    item => item.category === category
  )

  const formattedTitle =
    category.charAt(0).toUpperCase() + category.slice(1)

  return (

    <div className="min-h-screen bg-black text-white px-6 py-20">

      <div className="max-w-7xl mx-auto">

        <h1 className="text-7xl font-black mb-16">
          {formattedTitle}
        </h1>


        <div className="grid grid-cols-1 md:grid-cols-3 gap-10">

          {filteredProducts.map((product) => (

            <Link
              key={product.id}
              to={`/print/product/${product.id}`}
              className="group bg-[#0d0d0d] border border-[#1f1f1f] rounded-[32px] overflow-hidden hover:border-yellow-500 transition duration-500"
            >

              <div className="overflow-hidden">

                <img
                  src={product.image}
                  alt={product.name}
                  className="w-full h-[520px] object-cover group-hover:scale-110 transition duration-700"
                />

              </div>

              <div className="p-8">

                <h2 className="text-4xl font-black mb-4">
                  {product.name}
                </h2>

                <p className="text-yellow-500 text-2xl">
                  Starting at ${product.price}
                </p>

              </div>

            </Link>

          ))}

        </div>

      </div>
    </div>
  )
}
